// 1. Class Definition
class Person {
  #secret; // Private field (ES2022)

  constructor(name) {
    this.name = name;
    this.#secret = 'Internal Key';
  }

  greet() {
    return `Hi, I am ${this.name}`;
  }
}

// 2. Inheritance
class Employee extends Person {
  constructor(name, role) {
    super(name); // Calls the parent constructor
    this.role = role;
  }
}

codeExample1.code:
class BankAccount {
  #balance = 0; // Private field

  constructor(owner) {
    this.owner = owner;
  }

  deposit(amount) {
    if (amount > 0) this.#balance += amount;
  }

  get balance() {
    return `$${this.#balance}`;
  }

  set balance(val) {
    console.error('Cannot set balance directly!');
  }
}

const myAcc = new BankAccount('John');
myAcc.deposit(100);
console.log(myAcc.balance); // $100
myAcc.balance = 500; // Error log

codeExample2.code:
class Animal {
  constructor(name) {
    this.name = name;
  }

  makeSound() {
    console.log('Generic sound');
  }
}

class Dog extends Animal {
  makeSound() {
    console.log('Woof! Woof!');
  }
}

class Cat extends Animal {
  makeSound() {
    console.log('Meow!');
  }
}

const pets = [new Dog('Rex'), new Cat('Whiskers')];
pets.forEach(pet => pet.makeSound()); // Polymorphism in action
